const raw = $input.first().json.text;
const p0 = JSON.parse(raw.match(/\{[\s\S]*\}$/m)?.[0] || raw);
const ctx = $('Code: Calculate Metrics1').first().json;
return [{ json: { p0, company: ctx.company, answers: ctx.answers, flat: ctx.flat, metrics: ctx.metrics } }];

const secret = $input.first().json.headers['x-ribuzz-secret'];
const expected = "Preseed2026+*";
if (!secret || secret !== expected) {
  throw new Error('Invalid webhook secret');
}
const body = $input.first().json.body;
if (!body?.job_id || !body?.diagnostic_id) {
  throw new Error('Missing job_id or diagnostic_id');
}
return [{ json: { job_id: body.job_id, diagnostic_id: body.diagnostic_id } }];

const answers = $json.answers;
const mx = $json.metricas_extraidas || {};
const flat = {};
for (const a of answers) {
  const vars = (a.variable_bd || '').split(',').map(v => v.trim());
  for (const v of vars) flat[v] = a.is_unknown ? '' : (a.answer_text || '');
}
function parseToken(token) {
  const suffix = token.match(/(mm|m|k)$/)?.[1];
  let body = token.replace(/(mm|m|k)$/, '');
  if (body.includes('.') && body.includes(',')) body = body.replace(/\./g, '').replace(',', '.');
  else if (body.includes(',') && /\d{3}$/.test(body.split(',')[1])) body = body.replace(',', '');
  else if (body.includes(',')) body = body.replace(',', '.');
  else if (/^\d{1,3}(?:\.\d{3})+$/.test(body)) body = body.replace(/\./g, '');
  let parsed = Number.parseFloat(body);
  if (!Number.isFinite(parsed)) return 0;
  if (suffix === 'mm' || suffix === 'm') parsed *= 1e6;
  if (suffix === 'k') parsed *= 1e3;
  return parsed;
}
function num(value, fallback = 0) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'number') return Number.isFinite(value) ? value : fallback;
  const normalized = value.toString().trim().toLowerCase();
  const ranges = { menos_10:5,'10_30':20,'31_100':65,mas_100:120,'0':0,'1_5':3,'6_15':10.5,'16_30':23,mas_30:40,no_se:fallback };
  if (Object.prototype.hasOwnProperty.call(ranges, normalized)) return ranges[normalized];
  const clean = normalized.replace(/cop|pesos|peso|aprox\.?|aproximadamente|~|\$/g,'').replace(/\s+/g,'');
  const matches = clean.match(/\d+(?:[.,]\d+)*(?:mm|m|k)?/g);
  if (!matches) return fallback;
  const nums = matches.map(parseToken).filter(n => Number.isFinite(n));
  if (!nums.length) return fallback;
  return nums.length >= 2 ? (nums[0] + nums[1]) / 2 : nums[0];
}
function clampPct(v) { return Number.isFinite(v) ? Math.max(0, Math.min(v, 100)) : 0; }
function safeRound(v) { return Number.isFinite(v) ? Math.round(v) : 0; }
function pick(ex, fallback) { return (ex !== null && ex !== undefined) ? ex : fallback; }

const ventas    = pick(mx.ventas_mes,             num(flat.comercial_ventas_mes));
const clientes  = Math.max(pick(mx.clientes_actuales, num(flat.comercial_clientes_actuales, 1)), 1);
const nuevos    = pick(mx.clientes_nuevos_mes,    num(flat.comercial_clientes_nuevos || flat.ventas_30d));
const inversion = pick(mx.inversion_publicidad_mes, num(flat.comercial_inversion_mes));
const leads     = Math.max(pick(mx.leads_mes,     num(flat.comercial_leads_mes || flat.interesados_30d, 1)), 1);
const conv      = clampPct(pick(mx.tasa_conversion_pct, num(flat.comercial_tasa_conversion, leads > 0 ? (nuevos/leads)*100 : 0)));
const ticketDeclarado = pick(mx.ticket_promedio_cop, num(flat.ticket_promedio));
const ticket_medio    = ticketDeclarado > 0 ? ticketDeclarado : (ventas > 0 ? ventas/clientes : 0);
const cac    = nuevos > 0 ? inversion/nuevos : inversion;
const ltv    = ticket_medio * 12;
const ratio_cac_ticket = ticket_medio > 0 ? (cac/ticket_medio)*100 : 100;
const ratio_cac_ltv    = ltv > 0 ? (cac/ltv)*100 : 100;
const leads_perdidos   = safeRound(leads * (1 - conv/100));
const conversion_actual   = conv/100;
const conversion_objetivo = Math.min(conversion_actual + 0.1, 1);
const clientes_adicionales = safeRound(leads * (conversion_objetivo - conversion_actual));
const ingreso_potencial    = clientes_adicionales * ticket_medio;
const s_ticket  = Math.min(ticket_medio/1e6, 1)*100;
const s_cac     = Math.max(0, 100 - ratio_cac_ticket);
const s_conv    = Math.min(conv*2, 100);
const s_ltv_cac = Math.max(0, 100 - ratio_cac_ltv);
const salud_comercial = s_ticket*0.25 + s_cac*0.3 + s_conv*0.25 + s_ltv_cac*0.2;
const metrics = {
  ticket_medio: safeRound(ticket_medio), cac: safeRound(cac), ltv: safeRound(ltv),
  ratio_cac_ticket: Math.round(ratio_cac_ticket*10)/10,
  ratio_cac_ltv: Math.round(ratio_cac_ltv*10)/10,
  leads_perdidos, ingreso_potencial: safeRound(ingreso_potencial),
  salud_comercial: safeRound(salud_comercial),
  raw_numeric_inputs: { ventas, clientes, nuevos, inversion, leads, conversion_pct: conv, ticket_declarado: ticketDeclarado }
};
const company = $('Fetch Diagnostic + Company1').first().json;
return [{ json: { answers, flat, metrics, company } }];

