const raw = $input.first().json.text || '';
let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON block found');
  parsed = JSON.parse(match[0]);
} catch(e) {
  return [{ json: { scores: {}, score_global: 0, parse_error: e.message } }];
}
const scores = parsed.scores || {};
const values = Object.values(scores).filter(v => typeof v?.score === 'number');
const score_global = values.length
  ? Math.round((values.reduce((s, v) => s + v.score, 0) / values.length) * 10) / 10
  : 0;
// Pass p0 through from Prep Scorer Input
const p0 = $('Prep Scorer Input1').first().json.p0;
return [{ json: { scores, score_global, p0 } }];

const result = $input.first().json;
if (!result.scores || Object.keys(result.scores).length === 0) {
  throw new Error('Scorer sub-workflow returned empty scores. Check OpenAI response.');
}
return [{ json: result }];

