const d = $('Prep Persistence1').first().json;
const c = d.ctx.scores;

const sc = (k) => c[k]?.score ?? 0;
const esc = (v) => (v ?? '').toString().replace(/\$(?=\d)/g, 'USD').replace(/'/g, "''");
const jb = (v) => {
  const json = JSON.stringify(v ?? {}).replace(/\$(?=\d)/g, 'USD');
